def solve(n, edges, label):
    from collections import defaultdict
    graph = [[] for _ in range(n)]
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    total_masks = 1 << n
    dp = [[[-1] * n for _ in range(n)] for _ in range(total_masks)]
    best = 1

    for i in range(n):
        mask = 1 << i
        dp[mask][i][i] = 1

    for mask in range(total_masks):
        for i in range(n):
            if not (mask & (1 << i)):
                continue
            for j in range(n):
                if not (mask & (1 << j)):
                    continue
                if dp[mask][i][j] == -1:
                    continue
                current = dp[mask][i][j]
                if current > best:
                    best = current

                for k in graph[i]:
                    if mask & (1 << k):
                        continue
                    if label[k] == label[j]:
                        new_mask = mask | (1 << k)
                        candidate = current + 1
                        if candidate > dp[new_mask][k][j]:
                            dp[new_mask][k][j] = candidate

                for l in graph[j]:
                    if mask & (1 << l):
                        continue
                    if label[l] == label[i]:
                        new_mask = mask | (1 << l)
                        candidate = current + 1
                        if candidate > dp[new_mask][i][l]:
                            dp[new_mask][i][l] = candidate

                for k in graph[i]:
                    if mask & (1 << k):
                        continue
                    for l in graph[j]:
                        if k == l or (mask & (1 << l)):
                            continue
                        if label[k] == label[l]:
                            new_mask = mask | (1 << k) | (1 << l)
                            candidate = current + 2
                            if candidate > dp[new_mask][k][l]:
                                dp[new_mask][k][l] = candidate

    for mask in range(total_masks):
        for i in range(n):
            for j in range(n):
                if dp[mask][i][j] > best:
                    best = dp[mask][i][j]

    return best
