from collections import deque

def solve(n: int, edges: list[list[int]], label: str) -> int:
    graph = [[] for _ in range(n)]
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    total_masks = 1 << n
    dp = [[[False] * n for _ in range(n)] for _ in range(total_masks)]
    q = deque()
    ans = 0

    for u in range(n):
        mask = 1 << u
        if not dp[mask][u][u]:
            dp[mask][u][u] = True
            q.append((mask, u, u))
            ans = max(ans, 1)

    for u, v in edges:
        if label[u] == label[v]:
            mask = (1 << u) | (1 << v)
            if not dp[mask][u][v]:
                dp[mask][u][v] = True
                q.append((mask, u, v))
                ans = max(ans, 2)

    while q:
        mask, u, v = q.popleft()
        cnt = bin(mask).count("1")
        if u == v:
            for x in graph[u]:
                if mask & (1 << x):
                    continue
                for y in graph[u]:
                    if mask & (1 << y):
                        continue
                    if x == y:
                        continue
                    if label[x] == label[y]:
                        new_mask = mask | (1 << x) | (1 << y)
                        if not dp[new_mask][x][y]:
                            dp[new_mask][x][y] = True
                            q.append((new_mask, x, y))
                            ans = max(ans, cnt + 2)
        else:
            for x in graph[u]:
                if mask & (1 << x):
                    continue
                for y in graph[v]:
                    if mask & (1 << y):
                        continue
                    if x == y:
                        continue
                    if label[x] == label[y]:
                        new_mask = mask | (1 << x) | (1 << y)
                        if not dp[new_mask][x][y]:
                            dp[new_mask][x][y] = True
                            q.append((new_mask, x, y))
                            ans = max(ans, cnt + 2)
    return ans
```

